struct PulsingDot: View {
    var color: Color
    var size: CGFloat = 8
    @State private var animate = false

    var body: some View {
        ZStack {
            Circle()
                .fill(color)
                .scaleEffect(animate ? 1.9 : 1.0)
                .opacity(animate ? 0 : 0.22)
            Circle().fill(color)
        }
        .frame(width: size, height: size)
        .onAppear {
            withAnimation(.easeOut(duration: 1.9).repeatForever(autoreverses: false)) {
                animate = true
            }
        }
    }
}

