}

@Test(arguments: [0, 10, 25])
func totalPriceNeverExceedsSubtotal(discountPercent: Int) {
    let total = totalPriceCents(basePricePerWalkCents: 2500, walkCount: 2, discountPercent: discountPercent)
    #expect(total <= 5000)
}

